+                    ...(defaults?.elevenlabs?.voiceSettings ?? {}),
+                    ...(overrides?.elevenlabs?.voiceSettings ?? {}),
+                  }
+                : undefined,
+          }
+        : undefined,
+    openai:
+      defaults?.openai || overrides?.openai
